DROP TABLE IF EXISTS company_metric;
DROP TABLE IF EXISTS company;
CREATE TABLE company (
  name TEXT PRIMARY KEY,
  "Pavadinimas" TEXT,
  "Pagrindinis brandas" TEXT,
  "Įmonė" TEXT,
  "Svetainė" TEXT,
  "Rekvizitai URL" TEXT,
  "Facebook" TEXT,
  "Instagram" TEXT,
  "LinkedIn" TEXT,
  "EVRK v2 veiklos kodas" TEXT,
  "Kodas" TEXT,
  "PVM kodas" TEXT,
  "EVRK v2 veikla" TEXT,
  "Veikla (kūryba)" TEXT,
  "Veikla (PR)" TEXT,
  "Veikla (Digital media)" TEXT,
  "Veikla (PA)" TEXT,
  "Adresas" TEXT,
  "Miestas" TEXT,
  "El. paštas" TEXT,
  "Telefonas" TEXT,
  "Mobilus" TEXT,
  "Kredito rizika" TEXT,
  "Įregistruota" TEXT
);
CREATE TABLE company_metric (
  company TEXT NOT NULL REFERENCES company(name),
  metric  TEXT NOT NULL,
  year    INTEGER,
  value   REAL,
  change  REAL,
  PRIMARY KEY (company, metric, year)
);
